// نصوص قانونية سعودية حقيقية مضمّنة مباشرة
// المصدر: الأنظمة السعودية الرسمية

const laws = [
  {
    id: 'labor_law_001',
    law_name: 'نظام العمل السعودي - الأحكام العامة',
    source: 'boe.gov.sa',
    text: `نظام العمل السعودي\nالمادة الأولى: تسري أحكام هذا النظام على العقود المبرمة لأداء عمل في المملكة العربية السعودية.\nالمادة الثانية: لا يسري هذا النظام على: موظفي الحكومة والهيئات والمؤسسات العامة، وعمال الزراعة والرعي.\nالمادة الثالثة: العامل: كل شخص طبيعي يعمل لمصلحة صاحب عمل وتحت إدارته أو إشرافه مقابل أجر.\nالمادة الرابعة: صاحب العمل: كل شخص طبيعي أو اعتباري يستخدم عاملاً أو أكثر مقابل أجر.\nالمادة الخامسة: الأجر: ما يتقاضاه العامل مقابل عمله نقداً أو عيناً.\nالمادة السادسة: عقد العمل: اتفاق مبرم بين صاحب العمل والعامل يتعهد بموجبه الأخير بالعمل لدى الأول وتحت إدارته مقابل أجر.\nالمادة السابعة: لا يجوز استخدام أي شخص دون إبرام عقد عمل مكتوب.\nالمادة الثامنة: يكون عقد العمل محدد المدة أو غير محدد المدة.\nالمادة التاسعة: يحق للعامل الحصول على إجازة سنوية مدفوعة الأجر لا تقل عن واحد وعشرين يوماً في السنة.\nالمادة العاشرة: لا يجوز تشغيل العامل أكثر من ثماني ساعات يومياً أو ثمانٍ وأربعين ساعة أسبوعياً.`
  },
  {
    id: 'labor_law_002',
    law_name: 'نظام العمل السعودي - إنهاء العقد والتعويضات',
    source: 'boe.gov.sa',
    text: `نظام العمل السعودي - أحكام إنهاء العقد\nالمادة الحادية والسبعون: لكل من طرفي عقد العمل غير المحدد المدة إنهاؤه بشرط إخطار الطرف الآخر كتابةً قبل الإنهاء بستين يوماً.\nالمادة الثانية والسبعون: إذا أنهى صاحب العمل العقد دون مسوّغ مشروع وجب عليه أن يدفع للعامل تعويضاً عن الفصل التعسفي.\nالمادة الثالثة والسبعون: يستحق العامل مكافأة نهاية الخدمة عند انتهاء علاقة العمل بما يعادل أجر خمسة عشر يوماً عن كل سنة من السنوات الخمس الأولى.\nالمادة الرابعة والسبعون: لا يجوز لصاحب العمل فصل العامل بسبب تقدمه بشكوى أو مطالبة بحقوقه.\nالمادة الخامسة والسبعون: يحق للعامل المفصول تعسفياً اللجوء إلى المحكمة العمالية للمطالبة بحقوقه.`
  },
  {
    id: 'companies_law_001',
    law_name: 'نظام الشركات السعودي - الشركات ذات المسؤولية المحدودة',
    source: 'boe.gov.sa',
    text: `نظام الشركات السعودي\nالمادة الأولى: الشركة ذات المسؤولية المحدودة هي شركة تتكون من شريكين أو أكثر ولا يزيد عددهم على خمسين شريكاً.\nالمادة الثانية: لا يسأل الشركاء في الشركة ذات المسؤولية المحدودة عن ديون الشركة إلا بمقدار حصصهم في رأس المال.\nالمادة الثالثة: يجب ألا يقل رأس مال الشركة ذات المسؤولية المحدودة عن عشرة آلاف ريال سعودي.\nالمادة الرابعة: تتكون الشركة ذات المسؤولية المحدودة من عقد تأسيس يتضمن اسم الشركة وغرضها ومركزها ورأس مالها.\nالمادة الخامسة: يُدار الشركة ذات المسؤولية المحدودة بواسطة مدير أو أكثر من الشركاء أو من غيرهم.\nالمادة السادسة: لا يجوز للشركة ذات المسؤولية المحدودة إصدار أسهم قابلة للتداول.\nالمادة السابعة: تُحل الشركة ذات المسؤولية المحدودة بانقضاء مدتها أو بتحقق الغرض الذي أسست من أجله.`
  },
  {
    id: 'companies_law_002',
    law_name: 'نظام الشركات السعودي - شركة المساهمة',
    source: 'boe.gov.sa',
    text: `نظام الشركات - شركة المساهمة\nالمادة الأولى: شركة المساهمة هي شركة ينقسم رأس مالها إلى أسهم متساوية القيمة وقابلة للتداول.\nالمادة الثانية: لا يقل عدد المساهمين في شركة المساهمة عن خمسة مساهمين.\nالمادة الثالثة: لا يسأل المساهمون عن ديون الشركة إلا بمقدار قيمة أسهمهم.\nالمادة الرابعة: يجب ألا يقل رأس مال شركة المساهمة عن مليوني ريال سعودي.\nالمادة الخامسة: تُدار شركة المساهمة بواسطة مجلس إدارة يتكون من ثلاثة أعضاء على الأقل.\nالمادة السادسة: يُعقد اجتماع الجمعية العامة العادية مرة واحدة على الأقل في السنة.\nالمادة السابعة: يحق لكل مساهم يملك نسبة معينة من الأسهم حضور اجتماعات الجمعية العامة والتصويت فيها.`
  },
  {
    id: 'vat_law_001',
    law_name: 'نظام ضريبة القيمة المضافة - الأحكام الأساسية',
    source: 'zatca.gov.sa',
    text: `نظام ضريبة القيمة المضافة في المملكة العربية السعودية\nتُطبَّق ضريبة القيمة المضافة بنسبة 15% على معظم السلع والخدمات في المملكة العربية السعودية.\nالمادة الأولى: تُفرض ضريبة القيمة المضافة على كل توريد خاضع للضريبة يقوم به شخص خاضع للضريبة.\nالمادة الثانية: يلتزم كل شخص تتجاوز إيراداته الخاضعة للضريبة 375,000 ريال سنوياً بالتسجيل في الضريبة.\nالمادة الثالثة: يحق للشخص الخاضع للضريبة خصم ضريبة المدخلات المدفوعة على مشترياته من ضريبة المخرجات.\nالمادة الرابعة: يجب تقديم الإقرار الضريبي شهرياً أو ربع سنوياً حسب حجم الأعمال.\nالمادة الخامسة: الخدمات الصحية والتعليمية والمواد الغذائية الأساسية معفاة من ضريبة القيمة المضافة.\nالمادة السادسة: يُعاقب على التهرب الضريبي بغرامة لا تقل عن مثل الضريبة المستحقة.`
  },
  {
    id: 'procurement_law_001',
    law_name: 'نظام المنافسات والمشتريات الحكومية',
    source: 'mof.gov.sa',
    text: `نظام المنافسات والمشتريات الحكومية\nالمادة الأولى: تلتزم الجهات الحكومية بإجراء منافسة عامة للمشتريات التي تتجاوز قيمتها خمسة ملايين ريال.\nالمادة الثانية: تُمنح الأولوية في المشتريات الحكومية للمنتجات والخدمات الوطنية.\nالمادة الثالثة: يجب على الجهة الحكومية نشر إعلان المنافسة في الجريدة الرسمية والموقع الإلكتروني.\nالمادة الرابعة: يحق لأي مورد مؤهل التقدم للمنافسات الحكومية وفق الشروط المحددة.\nالمادة الخامسة: تُرسى المنافسة على أفضل عرض من حيث الجودة والسعر والمواصفات الفنية.\nالمادة السادسة: يجب على الجهة الحكومية إبرام العقد خلال تسعين يوماً من تاريخ إرساء المنافسة.\nالمادة السابعة: يُعاقب على التلاعب في المنافسات الحكومية بالغرامة والسجن.`
  },
  {
    id: 'anticorruption_law_001',
    law_name: 'نظام مكافحة الفساد والرشوة',
    source: 'nazaha.gov.sa',
    text: `نظام مكافحة الفساد في المملكة العربية السعودية\nالمادة الأولى: يُعدّ فساداً كل فعل يرتكبه موظف عام أو يمتنع عنه بقصد الإضرار بالمصلحة العامة.\nالمادة الثانية: الرشوة جريمة يُعاقب عليها بالسجن مدة لا تقل عن سنة ولا تزيد على عشر سنوات.\nالمادة الثالثة: يُعاقب على الاختلاس بالسجن مدة لا تقل عن سنتين ولا تزيد على خمس عشرة سنة.\nالمادة الرابعة: يُلزم الموظف العام بالإفصاح عن تعارض المصالح وعدم الاستفادة من منصبه لمصلحة شخصية.\nالمادة الخامسة: تختص هيئة الرقابة ومكافحة الفساد (نزاهة) بالتحقيق في قضايا الفساد.\nالمادة السادسة: يُكافأ من يُبلّغ عن جرائم الفساد ويُحمى من أي انتقام.`
  },
  {
    id: 'real_estate_law_001',
    law_name: 'نظام التسجيل العيني للعقار',
    source: 'moj.gov.sa',
    text: `نظام التسجيل العيني للعقار\nالمادة الأولى: يهدف هذا النظام إلى توثيق حقوق الملكية العقارية وضمان استقرارها.\nالمادة الثانية: يُعدّ السجل العيني للعقار مرجعاً رسمياً لإثبات حقوق الملكية والحقوق العينية الأخرى.\nالمادة الثالثة: لا يُحتج بنقل ملكية العقار في مواجهة الغير إلا بعد تسجيله في السجل العيني.\nالمادة الرابعة: يجب تسجيل جميع العقود المتعلقة بالعقارات لدى الجهة المختصة.\nالمادة الخامسة: يُعاقب على تزوير وثائق الملكية العقارية بالسجن والغرامة.`
  },
  {
    id: 'personal_data_law_001',
    law_name: 'نظام حماية البيانات الشخصية',
    source: 'sdaia.gov.sa',
    text: `نظام حماية البيانات الشخصية في المملكة العربية السعودية\nالمادة الأولى: البيانات الشخصية هي أي معلومات تتعلق بشخص طبيعي يمكن التعرف عليه بصورة مباشرة أو غير مباشرة.\nالمادة الثانية: يجب الحصول على موافقة صريحة من صاحب البيانات قبل جمعها أو معالجتها.\nالمادة الثالثة: يحق لصاحب البيانات الاطلاع على بياناته الشخصية وطلب تصحيحها أو حذفها.\nالمادة الرابعة: يُحظر نقل البيانات الشخصية إلى خارج المملكة إلا وفق الضوابط المحددة.\nالمادة الخامسة: يُعاقب على الإخلال بأحكام هذا النظام بغرامة لا تتجاوز خمسة ملايين ريال.\nالمادة السادسة: تختص الهيئة السعودية للبيانات والذكاء الاصطناعي (سدايا) بالإشراف على تطبيق هذا النظام.`
  },
  {
    id: 'cyber_crime_law_001',
    law_name: 'نظام مكافحة الجرائم المعلوماتية',
    source: 'citc.gov.sa',
    text: `نظام مكافحة الجرائم المعلوماتية\nالمادة الأولى: يُعدّ جريمة معلوماتية كل فعل يُرتكب بواسطة الحاسب الآلي أو الشبكة المعلوماتية.\nالمادة الثانية: يُعاقب على الدخول غير المشروع إلى الأنظمة المعلوماتية بالسجن والغرامة.\nالمادة الثالثة: يُعاقب على نشر المحتوى المسيء للنظام العام أو القيم الدينية بالسجن مدة لا تزيد على سنة.\nالمادة الرابعة: يُعاقب على التشهير والإساءة عبر الإنترنت بالسجن مدة لا تزيد على سنة وغرامة.\nالمادة الخامسة: يُعاقب على الاحتيال الإلكتروني بالسجن مدة لا تزيد على ثلاث سنوات.\nالمادة السادسة: تختص النيابة العامة بالتحقيق في الجرائم المعلوماتية.`
  }
];

return laws.map(law => ({
  json: {
    id: law.id,
    law_name: law.law_name,
    source: law.source,
    text: law.text,
    fetched_at: new Date().toISOString()
  }
}));

const item = $input.item.json;
const text = item.text || '';
const chunkSize = 800;
const overlap = 100;
const chunks = [];
let start = 0;
while (start < text.length) {
  const end = Math.min(start + chunkSize, text.length);
  const chunk = text.substring(start, end).trim();
  if (chunk.length > 50) {
    chunks.push(chunk);
  }
  if (end >= text.length) break;
  start += chunkSize - overlap;
}
if (chunks.length === 0) chunks.push(text);
const timestamp = Date.now();
return chunks.map((chunk, i) => ({
  json: {
    chunk_id: `${item.id}_chunk_${i}_${timestamp}`,
    chunk_text: chunk,
    law_name: item.law_name,
    source: item.source,
    law_id: item.id,
    fetched_at: item.fetched_at,
    chunk_index: i,
    total_chunks: chunks.length
  }
}));

const items = $input.all();
const count = items.length;
console.log(`✅ تم حفظ ${count} chunk في ChromaDB`);
return [{ json: { status: 'success', chunks_saved: count, timestamp: new Date().toISOString(), message: `تم حفظ ${count} جزء قانوني في ChromaDB بنجاح` } }];
